import requests
import json

KONG_ADMIN_URL = "http://localhost:8001"  # Replace with your Kong Admin API URL

def create_service(name, url):
    """
    Creates a new Service in Kong.
    """
    data = {
        "name": name,
        "url": url
    }
    response = requests.post(f"{KONG_ADMIN_URL}/services", json=data)
    response.raise_for_status()
    print(f"Service '{name}' created: {response.json()}")
    return response.json()

def create_route(service_id, paths=None, hosts=None, protocols=None, methods=None):
    """
    Creates a new Route for a given Service ID.
    At least one of 'paths', 'hosts', 'protocols', 'methods' must be provided.
    """
    data = {
        "service": {"id": service_id}
    }
    if paths:
        data["paths"] = paths
    if hosts:
        data["hosts"] = hosts
    if protocols:
        data["protocols"] = protocols
    if methods:
        data["methods"] = methods

    response = requests.post(f"{KONG_ADMIN_URL}/routes", json=data)
    response.raise_for_status()
    print(f"Route for service '{service_id}' created: {response.json()}")
    return response.json()

def create_upstream(name):
    """
    Creates a new Upstream in Kong.
    """
    data = {
        "name": name
    }
    response = requests.post(f"{KONG_ADMIN_URL}/upstreams", json=data)
    response.raise_for_status()
    print(f"Upstream '{name}' created: {response.json()}")
    return response.json()

def add_target_to_upstream(upstream_id, target_url, weight=100):
    """
    Adds a target to an existing Upstream.
    """
    data = {
        "target": target_url,
        "weight": weight
    }
    response = requests.post(f"{KONG_ADMIN_URL}/upstreams/{upstream_id}/targets", json=data)
    response.raise_for_status()
    print(f"Target '{target_url}' added to upstream '{upstream_id}': {response.json()}")
    return response.json()

if __name__ == "__main__":
    try:
        # Example 1: Create a simple service and route
        print("--- Configuring Example Service 1 ---")
        my_service = create_service("my-example-service", "http://mockbin.org")
        create_route(my_service["id"], paths=["/my-example-api"])

        # Example 2: Create a service pointing to an upstream, then create upstream and add targets
        print("\n--- Configuring Example Service 2 with Upstream ---")
        my_upstream = create_upstream("my-load-balanced-upstream")
        add_target_to_upstream(my_upstream["id"], "http://localhost:8081", weight=100)
        add_target_to_upstream(my_upstream["id"], "http://localhost:8082", weight=50)

        # Create a service that uses the upstream
        my_upstream_service = create_service("my-upstream-service", f"http://{my_upstream['name']}")
        create_route(my_upstream_service["id"], hosts=["api.example.com"], paths=["/upstream-path"])

        # Example 3: Create another service with multiple routes
        print("\n--- Configuring Example Service 3 with Multiple Routes ---")
        another_service = create_service("another-test-service", "http://httpbin.org/get")
        create_route(another_service["id"], paths=["/test-route-1"], methods=["GET"])
        create_route(another_service["id"], paths=["/test-route-2"], hosts=["my.app.com"])

        print("\nKong configuration complete!")

    except requests.exceptions.ConnectionError as e:
        print(f"Error: Could not connect to Kong Admin API at {KONG_ADMIN_URL}.")
        print("Please ensure Kong is running and the Admin API is accessible.")
